module top_module(
	input clk,
	input reset,
	output [3:0] count);logic [3:0] count_reg;

	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt)
		if (reset) count_reg = 4'b0000;
		else count_reg = {count_reg[2:0], ~count_reg[3]};

	assign count = count_reg;

endmodule
